    58→/* ── NAV ── */
    59→.topbar {
    60→  position: fixed; top: 0; left: 0; right: 0; height: 60px;
    61→  background: rgba(250,246,240,0.92); backdrop-filter: blur(12px);
    62→  border-bottom: 1px solid var(--border-light);
    63→  display: flex; align-items: center; justify-content: space-between;
    64→  padding: 0 clamp(1rem, 4vw, 3rem); z-index: 100;
    65→}
    66→.topbar-brand {
    67→  font-family: 'Fraunces', serif; font-weight: 700; font-size: 1.05rem;
    68→  color: var(--ink); display: flex; align-items: center; gap: 10px;
    69→}
    70→.topbar-brand .icon {
    71→  width: 28px; height: 28px; background: var(--accent); border-radius: 6px;
    72→  display: flex; align-items: center; justify-content: center;
    73→  color: #fff; font-family: 'DM Mono', monospace; font-size: 0.75rem; font-weight: 500;
    74→}
    75→.topbar-nav { display: flex; gap: 0.25rem; list-style: none; }
    76→.topbar-nav a {
    77→  font-family: 'DM Mono', monospace; font-size: 0.7rem; font-weight: 400;
    78→  color: var(--ink-muted); text-decoration: none; padding: 0.4rem 0.7rem;
    79→  border-radius: var(--radius-sm); transition: all 0.2s;
    80→  letter-spacing: 0.02em;
    81→}
    82→.topbar-nav a:hover { color: var(--accent); background: var(--accent-bg); }
    83→
    84→.progress-track {
    85→  position: fixed; top: 60px; left: 0; right: 0; height: 3px;
    86→  background: var(--border-light); z-index: 99;
    87→}
    88→.progress-fill {
    89→  height: 100%; width: 0%; background: linear-gradient(90deg, var(--accent), var(--accent-light));
    90→  transition: width 0.15s; border-radius: 0 2px 2px 0;
    91→}
    92→
    93→/* ── LAYOUT ── */
    94→.page { max-width: 780px; margin: 0 auto; padding: 0 clamp(1.25rem, 4vw, 2.5rem); }
    95→
    96→/* ── HERO ── */
    97→.hero {
    98→  padding: 7rem 0 4rem; text-align: center; position: relative;
    99→}
   100→.hero-badge {
   101→  display: inline-flex; align-items: center; gap: 6px;
   102→  font-family: 'DM Mono', monospace; font-size: 0.72rem; font-weight: 500;
   103→  color: var(--accent); background: var(--accent-bg);
   104→  padding: 0.35rem 1rem; border-radius: 20px; margin-bottom: 1.5rem;
   105→  letter-spacing: 0.04em;
   106→}
   107→.hero-badge .dot { width: 6px; height: 6px; background: var(--accent); border-radius: 50%; }
   108→.hero h1 {
   109→  font-family: 'Fraunces', serif; font-weight: 900;
