   113→.hero h1 em { font-style: normal; color: var(--accent); }
   114→.hero-desc {
   115→  font-size: 1.1rem; color: var(--ink-soft); max-width: 520px;
   116→  margin: 0 auto 2rem; font-style: italic; line-height: 1.7;
