   118→.hero-meta {
   119→  display: flex; justify-content: center; gap: 2.5rem; flex-wrap: wrap;
   120→}
   121→.hero-meta-item { text-align: center; }
   122→.hero-meta-item .val {
   123→  font-family: 'Fraunces', serif; font-weight: 700; font-size: 1.5rem;
   124→  color: var(--accent); display: block;
   125→}
   126→.hero-meta-item .lbl {
   127→  font-family: 'DM Mono', monospace; font-size: 0.65rem;
   128→  color: var(--ink-muted); text-transform: uppercase; letter-spacing: 0.1em;
   129→}
   130→
   131→/* ── TABLE OF CONTENTS ── */
   132→.toc {
   133→  background: var(--surface); border: 1px solid var(--border);
   134→  border-radius: var(--radius); padding: 2rem 2.25rem;
   135→  margin: 2rem 0 3rem; box-shadow: var(--shadow);
   136→}
   137→.toc-title {
   138→  font-family: 'DM Mono', monospace; font-size: 0.68rem; font-weight: 500;
   139→  color: var(--accent); text-transform: uppercase; letter-spacing: 0.14em;
   140→  margin-bottom: 1.25rem; display: flex; align-items: center; gap: 8px;
   141→}
   142→.toc-title::after { content: ''; flex: 1; height: 1px; background: var(--border); }
   143→.toc-list {
   144→  display: grid; grid-template-columns: repeat(auto-fill, minmax(310px, 1fr));
   145→  gap: 0.15rem 2rem; list-style: none;
   146→}
   147→.toc-list a {
   148→  display: flex; align-items: center; gap: 0.75rem;
   149→  font-family: 'Source Serif 4', serif; font-size: 0.92rem;
   150→  color: var(--ink-soft); text-decoration: none; padding: 0.4rem 0.5rem;
   151→  border-radius: var(--radius-sm); transition: all 0.2s;
   152→}
   153→.toc-list a:hover { color: var(--accent); background: var(--accent-bg); }
   154→.toc-num {
   155→  font-family: 'DM Mono', monospace; font-size: 0.68rem; font-weight: 500;
   156→  color: var(--ink-faint); min-width: 1.6rem; transition: color 0.2s;
   157→}
   158→.toc-list a:hover .toc-num { color: var(--accent); }
   159→
   160→/* ── LESSON SECTIONS ── */
   161→.lesson {
   162→  padding: 3.5rem 0 2.5rem;
   163→  border-bottom: 1px solid var(--border-light);
   164→  opacity: 0; transform: translateY(20px);
   165→  transition: opacity 0.5s ease, transform 0.5s ease;
   166→}
   167→.lesson.visible { opacity: 1; transform: translateY(0); }
   168→.lesson:last-of-type { border-bottom: none; }
   169→
   170→.lesson-head { display: flex; align-items: flex-start; gap: 1rem; margin-bottom: 1.75rem; }
   171→.lesson-num {
   172→  font-family: 'DM Mono', monospace; font-size: 0.65rem; font-weight: 500;
   173→  color: var(--accent); background: var(--accent-bg);
   174→  min-width: 2.4rem; height: 2.4rem; display: flex; align-items: center;
   175→  justify-content: center; border-radius: 8px; flex-shrink: 0; margin-top: 2px;
   176→  border: 1px solid rgba(196,77,43,0.15);
   177→}
   178→.lesson h2 {
   179→  font-family: 'Fraunces', serif; font-weight: 700; font-size: 1.7rem;
   180→  line-height: 1.2; letter-spacing: -0.015em; color: var(--ink);
   181→}
   182→
   183→.lesson h3 {
   184→  font-family: 'Fraunces', serif; font-weight: 600; font-size: 1.12rem;
   185→  color: var(--teal); margin: 2.25rem 0 0.75rem;
   186→  padding-bottom: 0.4rem; border-bottom: 2px solid var(--teal-bg);
   187→}
   188→
   189→.lesson p { margin-bottom: 1rem; color: var(--ink-soft); }
   190→.lesson strong { color: var(--ink); font-weight: 600; }
   191→
   192→/* ── ANALOGY BOX ── */
   193→.analogy {
   194→  background: var(--purple-bg); border: 1px solid rgba(107,76,154,0.15);
   195→  border-radius: var(--radius); padding: 1.4rem 1.6rem; margin: 1.5rem 0;
   196→  position: relative;
   197→}
   198→.analogy::before {
   199→  content: 'ANALOGY'; font-family: 'DM Mono', monospace;
   200→  font-size: 0.6rem; font-weight: 500; letter-spacing: 0.15em;
   201→  color: var(--purple); position: absolute; top: -0.5rem; left: 1.2rem;
   202→  background: var(--purple-bg); padding: 0 0.5rem;
   203→}
   204→.analogy p { color: var(--ink-soft); font-style: italic; margin: 0; font-size: 0.95rem; }
   205→
   206→/* ── CALLOUTS ── */
   207→.callout {
   208→  background: var(--surface); border: 1px solid var(--border);
   209→  border-radius: var(--radius); padding: 1.25rem 1.5rem; margin: 1.5rem 0;
   210→  border-left: 4px solid var(--teal);
   211→}
   212→.callout.warn { border-left-color: var(--accent); background: var(--accent-bg); }
   213→.callout.tip { border-left-color: var(--green); background: var(--green-bg); }
   214→.callout.info { border-left-color: var(--blue); background: var(--blue-bg); }
   215→.callout.gold { border-left-color: var(--gold); background: var(--gold-bg); }
   216→.callout-label {
   217→  font-family: 'DM Mono', monospace; font-size: 0.62rem; font-weight: 500;
   218→  letter-spacing: 0.13em; text-transform: uppercase; margin-bottom: 0.4rem;
   219→  display: block; color: var(--teal);
   220→}
   221→.callout.warn .callout-label { color: var(--accent); }
   222→.callout.tip .callout-label { color: var(--green); }
   223→.callout.info .callout-label { color: var(--blue); }
   224→.callout.gold .callout-label { color: var(--gold); }
   225→.callout p { font-size: 0.93rem; color: var(--ink-soft); margin: 0; }
   226→
   227→/* ── PROCESS STEPS ── */
   228→.steps { margin: 1.5rem 0; }
   229→.step {
   230→  display: flex; gap: 1rem; position: relative;
   231→  padding-bottom: 1.25rem;
   232→}
   233→.step:last-child { padding-bottom: 0; }
   234→.step-rail {
   235→  display: flex; flex-direction: column; align-items: center; width: 1.8rem; flex-shrink: 0;
   236→}
   237→.step-dot {
   238→  width: 10px; height: 10px; border-radius: 50%; border: 2.5px solid var(--accent);
   239→  background: var(--bg); flex-shrink: 0; margin-top: 0.55rem; position: relative; z-index: 1;
   240→}
   241→.step-line { width: 2px; flex: 1; background: var(--border); margin-top: 4px; }
   242→.step:last-child .step-line { display: none; }
   243→.step-body { flex: 1; padding-top: 0.15rem; }
   244→.step-title {
   245→  font-family: 'DM Mono', monospace; font-size: 0.75rem; font-weight: 500;
   246→  color: var(--accent); text-transform: uppercase; letter-spacing: 0.06em;
   247→  margin-bottom: 0.15rem;
   248→}
   249→.step-text { font-size: 0.92rem; color: var(--ink-soft); line-height: 1.6; }
   250→
   251→/* ── CODE BLOCKS ── */
   252→pre {
   253→  background: #1e1b18; color: #e0d8cc; border-radius: var(--radius);
   254→  padding: 1.3rem 1.5rem; margin: 1.25rem 0; overflow-x: auto;
   255→  position: relative; box-shadow: var(--shadow);
   256→  border: 1px solid rgba(0,0,0,0.1);
   257→}
   258→pre::before {
   259→  content: attr(data-lang); position: absolute; top: 0; right: 0;
   260→  font-family: 'DM Mono', monospace; font-size: 0.58rem; letter-spacing: 0.1em;
   261→  text-transform: uppercase; color: #8a7e6a; padding: 0.3rem 0.8rem;
   262→  background: rgba(255,255,255,0.04); border-radius: 0 var(--radius) 0 var(--radius-sm);
   263→}
   264→code {
   265→  font-family: 'DM Mono', monospace; font-size: 0.84rem; line-height: 1.7;
   266→}
   267→p code, li code, td code {
   268→  background: var(--gold-bg); border: 1px solid rgba(161,124,46,0.2);
   269→  color: var(--gold); padding: 0.12em 0.4em; font-size: 0.82rem;
   270→  border-radius: 4px;
   271→}
   272→.ck { color: #f0836a; } .cs { color: #d4c47a; } .cc { color: #6b6358; font-style: italic; }
   273→.cn { color: #7cc5bd; } .cf { color: #8dc77b; } .cv { color: #e0b060; }
   274→
   275→/* ── TABLES ── */
   276→.table-wrap { overflow-x: auto; margin: 1.5rem 0; border-radius: var(--radius); box-shadow: var(--shadow); }
   277→table { width: 100%; border-collapse: collapse; background: var(--surface); font-size: 0.92rem; }
   278→thead th {
   279→  font-family: 'DM Mono', monospace; font-size: 0.68rem; font-weight: 500;
   280→  letter-spacing: 0.08em; text-transform: uppercase; color: var(--accent);
   281→  padding: 0.8rem 1.1rem; text-align: left; background: var(--accent-bg);
   282→  border-bottom: 2px solid rgba(196,77,43,0.15);
   283→}
   284→tbody td {
   285→  padding: 0.75rem 1.1rem; border-bottom: 1px solid var(--border-light);
   286→  color: var(--ink-soft); vertical-align: top;
   287→}
   288→tbody tr:last-child td { border-bottom: none; }
   289→tbody tr:hover td { background: rgba(196,77,43,0.02); }
   290→.badge {
   291→  display: inline-block; font-family: 'DM Mono', monospace; font-size: 0.68rem;
   292→  padding: 0.15em 0.6em; border-radius: 4px; font-weight: 500;
   293→}
   294→.badge-yes { background: var(--green-bg); color: var(--green); }
   295→.badge-no { background: var(--accent-bg); color: var(--accent); }
   296→
   297→/* ── SHORTCUT GRID ── */
   298→.card-grid {
   299→  display: grid; grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
