  1001→<script>
  1002→// Progress bar
  1003→const fill = document.getElementById('progressFill');
  1004→const toTop = document.getElementById('toTop');
  1005→window.addEventListener('scroll', () => {
  1006→  const s = window.scrollY;
  1007→  const t = document.documentElement.scrollHeight - window.innerHeight;
  1008→  fill.style.width = (s / t * 100) + '%';
  1009→  toTop.classList.toggle('show', s > 500);
  1010→}, { passive: true });
  1011→
  1012→// Intersection observer for lesson reveal
  1013→const obs = new IntersectionObserver(entries => {
  1014→  entries.forEach(e => { if (e.isIntersecting) { e.target.classList.add('visible'); obs.unobserve(e.target); } });
  1015→}, { threshold: 0.06 });
  1016→document.querySelectorAll('.lesson').forEach(l => obs.observe(l));
  1017→
  1018→// Checkboxes
  1019→document.querySelectorAll('.check-item').forEach(item => {
  1020→  item.querySelector('input').addEventListener('change', function() {
  1021→    item.classList.toggle('checked', this.checked);
  1022→  });
  1023→});
  1024→
  1025→// ── Count-up animation ──
  1026→function animateCountUp(el) {
  1027→  const target = parseFloat(el.dataset.target);
  1028→  const suffix = el.dataset.suffix || '';
  1029→  const decimals = parseInt(el.dataset.decimals || '0', 10);
  1030→  const duration = 1600;
  1031→  const startTime = performance.now();
  1032→
  1033→  function easeOutCubic(t) { return 1 - Math.pow(1 - t, 3); }
  1034→
  1035→  function tick(now) {
  1036→    const elapsed = now - startTime;
  1037→    const progress = Math.min(elapsed / duration, 1);
  1038→    const eased = easeOutCubic(progress);
  1039→    const current = target * eased;
  1040→    el.textContent = current.toFixed(decimals) + suffix;
  1041→    if (progress < 1) {
  1042→      requestAnimationFrame(tick);
  1043→    } else {
  1044→      el.textContent = target.toFixed(decimals) + suffix;
  1045→    }
  1046→  }
  1047→  requestAnimationFrame(tick);
  1048→}
