main {
  max-width: 880px;
  margin: 0 auto;
  padding: clamp(32px, 5vw, 56px) clamp(16px, 5vw, 32px) 100px;
  position: relative;
  z-index: 1;
}

/* ─── Section ─── */
.section {
  margin-bottom: clamp(56px, 8vw, 88px);
  animation: riseIn 0.5s ease-out both;
}

@keyframes riseIn {
  from { opacity: 0; transform: translateY(20px); }
  to   { opacity: 1; transform: translateY(0); }
}

.section-label {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 14px;
}

.section-num {
  font-family: 'Fira Code', monospace;
  font-size: 0.68rem;
  font-weight: 600;
  letter-spacing: 1px;
  padding: 3px 10px;
  border-radius: 100px;
  border: 1px solid;
}
.n-green  { color: var(--green); border-color: var(--green); background: var(--green-glow); }
.n-amber  { color: var(--amber); border-color: var(--amber); background: var(--amber-glow); }
.n-terra  { color: var(--terra); border-color: var(--terra); background: var(--terra-glow); }
.n-sage   { color: var(--sage);  border-color: var(--sage);  background: rgba(92,122,78,.1); }
.n-blue   { color: var(--blue);  border-color: var(--blue);  background: var(--blue-glow); }

.section-tag {
  font-size: 0.7rem;
  font-weight: 700;
  letter-spacing: 1.5px;
  text-transform: uppercase;
  color: var(--ink-4);
}

.section-title {
  font-family: 'Fraunces', serif;
  font-size: clamp(1.7rem, 4vw, 2.6rem);
  font-weight: 700;
  line-height: 1.1;
  letter-spacing: -1px;
  color: var(--ink);
  margin-bottom: 8px;
  overflow-wrap: break-word;
  word-break: break-word;
}

.section-sub {
  color: var(--ink-3);
  font-size: 0.92rem;
  max-width: 600px;
  font-weight: 400;
  margin-bottom: 28px;
  line-height: 1.65;
}

/* ─── Divider ─── */
.divider {
  height: 1px;
  background: linear-gradient(90deg, transparent, var(--border-strong) 30%, var(--border-strong) 70%, transparent);
  margin: clamp(36px, 5vw, 56px) 0;
  position: relative;
}
.divider::after {
  content: '◆';
  position: absolute;
  left: 50%;
  top: 50%;
  transform: translate(-50%, -50%);
  background: var(--bg);
  padding: 0 10px;
  color: var(--ink-4);
  font-size: 0.55rem;
}

/* ─── Card ─── */
.card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: clamp(18px, 4vw, 28px);
  margin-bottom: 18px;
  box-shadow: var(--shadow-sm);
  transition: border-color 0.25s, box-shadow 0.25s;
}
.card:hover {
  border-color: var(--border-strong);
  box-shadow: var(--shadow-md);
}

.card-head {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-bottom: 18px;
}

.card-ico {
  width: 42px; height: 42px;
  border-radius: 10px;
  display: flex; align-items: center; justify-content: center;
  font-size: 1.15rem;
  border: 1px solid var(--border);
  background: var(--bg-elevated);
  flex-shrink: 0;
}

.card-title {
  font-weight: 700;
  font-size: 1rem;
  color: var(--ink);
}

.card p, .card li {
  color: var(--ink-3);
  font-size: 0.88rem;
  line-height: 1.75;
}

.card ul { list-style: none; padding: 0; }
.card ul li {
  position: relative;
  padding-left: 18px;
  margin-bottom: 5px;
}
.card ul li::before {
  content: '→';
  position: absolute;
  left: 0;
  color: var(--green);
  font-weight: 700;
  font-size: 0.8rem;
}

/* ─── Table ─── */
.tbl-wrap { overflow-x: auto; margin: 12px 0; -webkit-overflow-scrolling: touch; }
table.styled {
  width: 100%;
  border-collapse: collapse;
  font-size: 0.84rem;
  min-width: 420px;
}
table.styled th {
  text-align: left;
  padding: 10px 14px;
  font-size: 0.7rem;
  font-weight: 700;
  letter-spacing: 0.8px;
  text-transform: uppercase;
  color: var(--ink-3);
  border-bottom: 1px solid var(--border-strong);
  white-space: nowrap;
}
table.styled td {
  padding: 10px 14px;
  border-bottom: 1px solid var(--border);
  color: var(--ink-3);
  vertical-align: top;
}
table.styled td:first-child {
  font-family: 'Fira Code', monospace;
  font-size: 0.8rem;
  color: var(--green);
  white-space: nowrap;
}
table.styled tr:last-child td { border-bottom: none; }
table.styled tbody tr:hover { background: var(--bg-elevated); }

/* ─── OS Tabs ─── */
.tab-strip {
  display: flex;
  gap: 2px;
  background: var(--bg-elevated);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 3px;
  width: fit-content;
  max-width: 100%;
  margin-bottom: 18px;
  flex-wrap: wrap;
}
.tab-btn {
  padding: 7px 16px;
  border-radius: 6px;
  font-size: 0.78rem;
  font-weight: 700;

