/* ─── Hero ─── */
.hero {
  position: relative;
  z-index: 1;
  padding: clamp(60px, 10vw, 110px) clamp(16px, 5vw, 40px) clamp(50px, 8vw, 80px);
  text-align: center;
  overflow: hidden;
}

.hero > * {
  max-width: 900px;
  margin-left: auto;
  margin-right: auto;
}

.hero-eyebrow {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 6px 16px;
  border: 1px solid var(--border-strong);
  border-radius: 100px;
  background: var(--bg-card);
  font-size: 0.72rem;
  font-weight: 700;
  letter-spacing: 1.5px;
  text-transform: uppercase;
  color: var(--green);
  margin-bottom: 28px;
}

.hero-eyebrow .pulse {
  width: 7px; height: 7px;
  border-radius: 50%;
  background: var(--green-light);
  animation: breathe 2.5s ease-in-out infinite;
  flex-shrink: 0;
}

@keyframes breathe {
  0%, 100% { opacity: 1; transform: scale(1); }
  50% { opacity: 0.35; transform: scale(0.7); }
}

.hero h1 {
  font-family: 'Fraunces', serif;
  font-size: clamp(2.4rem, 7vw, 5.5rem);
  font-weight: 900;
  line-height: 1.05;
  letter-spacing: -2px;
  color: var(--ink);
  margin-bottom: 12px;
  overflow-wrap: break-word;
  word-break: break-word;
}

.hero h1 em {
  font-style: italic;
  color: var(--green);
}

.hero .tagline {
  font-size: clamp(0.9rem, 2vw, 1.1rem);
  color: var(--ink-3);
  max-width: 560px;
  margin: 16px auto 0;
  font-weight: 400;
  line-height: 1.65;
}

.hero-platforms {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: 10px;
  margin-top: 32px;
}

.platform-pill {
  display: inline-flex;
  align-items: center;
  gap: 7px;
  padding: 8px 18px;
  border-radius: 100px;
  border: 1px solid var(--border-strong);
  background: var(--bg-card);
  font-size: 0.78rem;
  font-weight: 600;
  color: var(--ink-2);
  letter-spacing: 0.3px;
  transition: all 0.2s;
  box-shadow: var(--shadow-sm);
}

.platform-pill:hover {
  border-color: var(--green);
  color: var(--green);
  transform: translateY(-1px);
  box-shadow: var(--shadow-md);
}

